 }
+/// Fold fcmp pred (select (fcmp Pred1 X, 0.0), X, -X), 0.0 to fcmp pred X, 0.0.
+/// Fold fcmp pred (select Cond, X, -X), 0.0 to fcmp pred X, 0.0 for predicates
+/// where the sign of zero does not matter (equality, inequality, ordered/unordered).
+static Instruction *foldFCmpSelectXNegXWithZero(FCmpInst &I, InstCombinerImpl &IC) {
+  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
+  // RHS must be zero.
+  if (!match(Op1, m_AnyZeroFP()))
+    return nullptr;
+
+  Value *Cond, *TrueVal, *FalseVal;
+  if (!match(Op0, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal))))
+    return nullptr;
+
+  // Ensure that TrueVal and FalseVal are X and -X in some order.
+  Value *X;
+  if (!match(TrueVal, m_Specific(FalseVal))) {
+    // Not the same value, maybe one is neg of the other.
+    if (match(TrueVal, m_FNeg(m_Specific(FalseVal))))
+      X = FalseVal;
+    else if (match(FalseVal, m_FNeg(m_Specific(TrueVal))))
+      X = TrueVal;
+    else
+      return nullptr;
+  } else {
+    // TrueVal == FalseVal, select reduces to that value, but that would have been folded already.
+    return nullptr;
+  }
+
+  // Predicates where sign of zero does not affect the result.
+  switch (I.getPredicate()) {
+  case FCmpInst::FCMP_OEQ:
+  case FCmpInst::FCMP_UEQ:
+  case FCmpInst::FCMP_ONE:
+  case FCmpInst::FCMP_UNE:
+  case FCmpInst::FCMP_ORD:
+  case FCmpInst::FCMP_UNO:
+    break;
+  default:
+    return nullptr;
+  }
+
+  // Replace the compare with X vs zero.
+  return new FCmpInst(I.getPredicate(), X, Op1, "", &I);
+}

 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
@@ -8068,6 +8112,9 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   }
   }

+  if (Instruction *R = foldFCmpSelectXNegXWithZero(I, *this))
+    return R;
+
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

